proof_block:
// `next_set_request_postconditions` (and friends) are `#[verifier::opaque]`;
// freshly revealing them on entry exposes every conjunct from the spec at
// this proof point.  `reveal` is idempotent so this is safe even though the
// template prelude reveals the same set later.
reveal(HostState::next_set_request_postconditions);
reveal(HostState::next_set_request_preconditions);
reveal(HostState::host_state_common_postconditions);
reveal(HostState::host_state_common_preconditions);
reveal(HostState::host_state_packet_preconditions);

// The downstream `next_set_request(...)` assertion has a
// `pre.delegation_map.is_complete()` recommends-clause.  Under the
// requires, `host_state_common_preconditions` forces `pre_self_.valid()`,
// which in turn yields `pre_self_.delegation_map.valid()`.  Calling
// `valid_implies_complete` discharges the recommendation up front, so
// later `next_set_request(pre_self_@, ..., out)` unfolds are not gated by
// an unresolved recommendation.
if pre_self_.received_packet is Some {
    pre_self_.delegation_map.valid_implies_complete();
    assert(pre_self_@.delegation_map.0.dom().is_full());
    assert(pre_self_@.delegation_map.is_complete());
}

// The synthetic postcondition has the form `(PC1 && PC2) ==> det_equal`;
// we discharge it by entering the antecedent branch and surfacing every
// trigger needed to make both `next_set_request_postconditions` line up.
if post1_self_.next_set_request_postconditions(pre_self_, r1@)
    && post2_self_.next_set_request_postconditions(pre_self_, r2@)
{
    // `host_state_common_preconditions` rejects `None` received-packets,
    // so under the (revealed) precondition `received_packet` must be Some.
    // Naming the underlying packet once stabilises every later trigger
    // that goes through `pre_self_.received_packet.unwrap()`.
    assert(pre_self_.received_packet is Some);
    let cp = pre_self_.received_packet.unwrap();
    assert(pre_self_.received_packet.unwrap() == cp);
    assert(pre_self_@.received_packet is Some);
    assert(pre_self_@.received_packet.unwrap() == cp@);
    assert(cp.msg is Message);
    assert(cp.msg.arrow_Message_m() is SetRequest);

    // Stable names for the abstracted outbound-packet sets.  Both
    // `next_set_request_postconditions` instances reference exactly this
    // expression for their `out` argument; binding the name lets z3 line
    // up the same term across the two runs.
    let out1: Set<Packet> = abstractify_seq_of_cpackets_to_set_of_sht_packets(r1@);
    let out2: Set<Packet> = abstractify_seq_of_cpackets_to_set_of_sht_packets(r2@);

    // ----- host_state_common_postconditions conjuncts surfaced on each
    //       side so the corresponding `r1@` / `r2@` trigger terms both
    //       appear at the same proof point. -----
    assert(post1_self_.abstractable());
    assert(post2_self_.abstractable());
    assert(post1_self_.constants == pre_self_.constants);
    assert(post2_self_.constants == pre_self_.constants);
    assert(post1_self_.constants == post2_self_.constants);
    assert(cpacket_seq_is_abstractable(r1@));
    assert(cpacket_seq_is_abstractable(r2@));
    assert(post1_self_.valid());
    assert(post2_self_.valid());
    assert(post1_self_.next_action_index == pre_self_.next_action_index);
    assert(post2_self_.next_action_index == pre_self_.next_action_index);
    assert(outbound_packet_seq_is_valid(r1@));
    assert(outbound_packet_seq_is_valid(r2@));
    assert(outbound_packet_seq_has_correct_srcs(r1@, pre_self_.constants.me@));
    assert(outbound_packet_seq_has_correct_srcs(r2@, pre_self_.constants.me@));

    // Per-index `msg`-shape forall: re-assert separately so the
    // disjoint `#[trigger]` instances both fire at this proof point.
    assert(forall|i: int| 0 <= i && i < r1@.len() ==>
        (#[trigger] r1@[i].msg) is Message || r1@[i].msg is Ack);
    assert(forall|i: int| 0 <= i && i < r2@.len() ==>
        (#[trigger] r2@[i].msg) is Message || r2@[i].msg is Ack);

    // LSHT `=~=` identity for each run; ping z3 to register both
    // abstractified outbound-packet sets.
    assert(out1 =~= extract_packets_from_lsht_packets(
        abstractify_outbound_packets_to_seq_of_lsht_packets(r1@)));
    assert(out2 =~= extract_packets_from_lsht_packets(
        abstractify_outbound_packets_to_seq_of_lsht_packets(r2@)));

    assert(post1_self_.resend_count < 100000000);
    assert(post2_self_.resend_count < 100000000);

    // `received_packet is None` after the step is an explicit conjunct
    // of `next_set_request_postconditions`; lift to the abstract view.
    assert(post1_self_.received_packet is None);
    assert(post2_self_.received_packet is None);
    assert(post1_self_@.received_packet is None);
    assert(post2_self_@.received_packet is None);
    assert(post1_self_@.received_packet == post2_self_@.received_packet);

    // ----- Abstract step relation `next_set_request` on each run; the
    //       call shares the same `cp@` argument across the two runs, so
    //       the existential body and the explicit `delegation_map` /
    //       `num_delegations` conjuncts are exposed identically. -----
    assert(next_set_request(pre_self_@, post1_self_@, cp@, out1));
    assert(next_set_request(pre_self_@, post2_self_@, cp@, out2));

    // `next_set_request` pins `delegation_map` and `num_delegations`
    // directly to `pre`; the view inherits that pinning.
    assert(post1_self_@.delegation_map == pre_self_@.delegation_map);
    assert(post2_self_@.delegation_map == pre_self_@.delegation_map);
    assert(post1_self_@.delegation_map == post2_self_@.delegation_map);
    assert(post1_self_@.num_delegations == pre_self_@.num_delegations);
    assert(post2_self_@.num_delegations == pre_self_@.num_delegations);
    assert(post1_self_@.num_delegations == post2_self_@.num_delegations);

    // `host_state_common_postconditions` pins `constants` concretely; the
    // view lifts to abstract `constants` equality on each run.
    assert(post1_self_@.constants == pre_self_@.constants);
    assert(post2_self_@.constants == pre_self_@.constants);
    assert(post1_self_@.constants == post2_self_@.constants);
    assert(post1_self_@.constants.view() == post2_self_@.constants.view());

    // `received_packet is Some`-conjunct of `det_equal` collapses: both
    // sides are `None`, so the equality `Some==Some` holds vacuously and
    // the conditional `is Some ==> (dst,src,msg agree)` is vacuous.
    assert(!(post1_self_@.received_packet is Some));
    assert(!(post2_self_@.received_packet is Some));
    assert((post1_self_@.received_packet is Some)
        == (post2_self_@.received_packet is Some));
    assert((post1_self_@.received_packet is Some) ==>
        ((post1_self_@.received_packet->Some_0.dst.view()
              == post2_self_@.received_packet->Some_0.dst.view())
         && (post1_self_@.received_packet->Some_0.src.view()
              == post2_self_@.received_packet->Some_0.src.view())
         && (post1_self_@.received_packet->Some_0.msg
              == post2_self_@.received_packet->Some_0.msg)));
}
